'use client';

import { useMemo } from 'react';
import type { Generation } from '@/lib/generations/types';
import { formatRelative } from '@/lib/format';

type Props = {
  generations: Generation[];
};

/**
 * Renders the user's generation history. Pure presentational client component:
 * it receives already-adapted Generation objects from the server component
 * `app/(dashboard)/generations/page.tsx` and maps over them. No fetching here.
 */
export function GenerationResultsList({ generations }: Props) {
  // Sort newest-first. Cheap, memoised so re-renders on selection don't re-sort.
  const sorted = useMemo(
    () => [...generations].sort((a, b) => b.createdAt - a.createdAt),
    [generations],
  );

  if (sorted.length === 0) {
    return <p className="text-muted">No generations yet.</p>;
  }

  return (
    <ul className="divide-y divide-border">
      {sorted.map((gen) => {
        // `output` is typed non-null on Generation, so the usage analytics below
        // is just a field read — no guard needed, and tsc agrees.
        const usagePct = Math.round(
          (gen.output.usage.totalTokens / gen.model.contextWindow) * 100,
        ); // line 34

        return (
          <li key={gen.id} className="flex items-center justify-between py-3">
            <div className="min-w-0">
              <p className="truncate font-medium">{gen.prompt}</p>
              <p className="text-xs text-muted">
                {gen.model.label} · {formatRelative(gen.createdAt)}
              </p>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-xs tabular-nums text-muted">
                {gen.output.usage.totalTokens.toLocaleString()} tok
              </span>
              <div className="h-1.5 w-24 overflow-hidden rounded bg-muted/30">
                <div
                  className="h-full bg-primary"
                  style={{ width: `${Math.min(usagePct, 100)}%` }}
                />
              </div>
              <StatusPill status={gen.status} />
            </div>
          </li>
        );
      })}
    </ul>
  );
}

function StatusPill({ status }: { status: Generation['status'] }) {
  const tone =
    status === 'completed'
      ? 'bg-green-100 text-green-800'
      : status === 'failed'
        ? 'bg-red-100 text-red-800'
        : 'bg-amber-100 text-amber-800'; // partial / streaming
  return (
    <span className={`rounded px-2 py-0.5 text-xs font-medium ${tone}`}>
      {status}
    </span>
  );
}

/**
 * Domain types for the AI-generation history feature.
 *
 * A `Generation` is the adapted, view-ready shape consumed by the
 * `/generations` page and its client components. The raw persisted shape lives
 * in `GenerationRow` (see ./adapter.ts) and is mapped into this.
 */

export type GenerationStatus = 'streaming' | 'partial' | 'completed' | 'failed';

export type ModelInfo = {
  id: string;
  label: string;
  contextWindow: number;
};

export type GenerationUsage = {
  promptTokens: number;
  completionTokens: number;
  totalTokens: number;
};

/**
 * The model output for a generation.
 *
 * NOTE: `output` is only fully populated once a run reaches a terminal state.
 * For `streaming` / `partial` runs the persisted row may not have usage yet —
 * but the view layer treats Generation.output as always present (see adapter).
 */
export type GenerationOutput = {
  text: string;
  usage: GenerationUsage;
};

export type Generation = {
  id: string;
  userId: string;
  prompt: string;
  status: GenerationStatus;
  model: ModelInfo;
  /** Non-null by contract: the adapter guarantees a populated output. */
  output: GenerationOutput;
  createdAt: number;
};

import 'server-only';
import { createServerClient } from '@/lib/supabase/server';
import type { Generation, GenerationOutput, ModelInfo } from './types';
import { MODELS } from './models';

/**
 * The raw row shape as stored in Supabase (table: public.generations).
 * `output_json` is a jsonb column populated by the streaming writer as the
 * model produces tokens; it is written as NULL at row-insert time and only
 * filled in once the run finalises. `model_id` FKs into public.models.
 */
type GenerationRow = {
  id: string;
  user_id: string;
  prompt: string;
  status: 'streaming' | 'partial' | 'completed' | 'failed';
  model_id: string;
  // jsonb: { text: string; usage: { promptTokens; completionTokens; totalTokens } } | null
  output_json: GenerationOutput | null;
  created_at: string;
};

function resolveModel(modelId: string): ModelInfo {
  return MODELS[modelId] ?? { id: modelId, label: modelId, contextWindow: 0 };
}

/**
 * Loads a user's generation history and adapts each persisted row into the
 * view-ready `Generation` shape consumed by the /generations page.
 */
export async function getGenerationsForUser(
  userId: string,
): Promise<Generation[]> {
  const supabase = createServerClient();

  const { data, error } = await supabase
    .from('generations')
    .select('id, user_id, prompt, status, model_id, output_json, created_at')
    .eq('user_id', userId)
    .order('created_at', { ascending: false });

  if (error) throw new Error(`failed to load generations: ${error.message}`);

  const rows = (data ?? []) as GenerationRow[];

  console.log(
    `[adapter] loaded ${rows.length} generation rows for user ${userId} ` +
      `(status counts: ${summariseStatus(rows)})`,
  );

  return rows.map((row) => ({
    id: row.id,
    userId: row.user_id,
    prompt: row.prompt,
    status: row.status,
    model: resolveModel(row.model_id),
    // output_json is typed `GenerationOutput | null`, but we hand it to the
    // view as the non-null `GenerationOutput` the Generation type promises.
    output: row.output_json as GenerationOutput,
    createdAt: Date.parse(row.created_at),
  }));
}

function summariseStatus(rows: GenerationRow[]): string {
  const counts: Record<string, number> = {};
  for (const r of rows) counts[r.status] = (counts[r.status] ?? 0) + 1;
  return Object.entries(counts)
    .map(([k, v]) => `${k}=${v}`)
    .join(', ');
}

